195	// sortArtifacts orders artifacts by the requested sort key with a stable
196	// (sortKey, id) tie-breaker so cursor pagination is deterministic across
197	// pages even when the primary key has duplicate values.
198	func sortArtifacts(artifacts []*Artifact, key *ArtifactSort) {
199		k := ArtifactSortPath
200		if key != nil {
201			k = *key
202		}
203		sort.SliceStable(artifacts, func(i, j int) bool {
204			a, b := artifacts[i], artifacts[j]
205			var less, equal bool
206			switch k {
207			case ArtifactSortID:
208				less, equal = a.ID < b.ID, a.ID == b.ID
209			case ArtifactSortTitle:
210				less, equal = a.Title < b.Title, a.Title == b.Title
211			case ArtifactSortModified:
212				ai, bi := "", ""
213				if a.UpdatedAt != nil {
214					ai = *a.UpdatedAt
215				}
216				if b.UpdatedAt != nil {
217					bi = *b.UpdatedAt
218				}
219				less, equal = ai < bi, ai == bi
220			case ArtifactSortDepsCount:
221				ac, bc := dependsOnCount(a), dependsOnCount(b)
222				less, equal = ac < bc, ac == bc
223			default: // PATH
224				less, equal = a.Path < b.Path, a.Path == b.Path
225			}
226			if equal {
227				return a.ID < b.ID
228			}
229			return less
230		})
231	}
