233	// matchesPhase reports whether a path falls under docs/helix/<phase>/.
234	// It accepts either an exact directory name match (e.g. "01-frame") or
235	// a numeric prefix match (e.g. "01") matching docs/helix/01-*/.
236	func matchesPhase(path, phase string) bool {
237		const root = "docs/helix/"
238		p := filepath.ToSlash(path)
239		if !strings.HasPrefix(p, root) {
240			return false
241		}
242		rest := p[len(root):]
243		slash := strings.IndexByte(rest, '/')
244		if slash < 0 {
245			return false
246		}
247		dir := rest[:slash]
248		if dir == phase {
249			return true
250		}
251		// numeric prefix match: phase="01" matches dir="01-frame"
252		if dash := strings.IndexByte(dir, '-'); dash > 0 && dir[:dash] == phase {
253			return true
254		}
255		return false
256	}
257	
258	// idPrefixSegment extracts the leading prefix segment from an artifact ID.
259	// IDs are typically formatted as "doc:<PREFIX>-..." (e.g. "doc:ADR-001-foo")
260	// or "<PREFIX>-..." for sidecar artifacts. The "doc:" / "sidecar:" namespace
261	// prefix, if present, is stripped before extraction. Returns empty string
262	// when no prefix segment can be identified.
263	func idPrefixSegment(id string) string {
264		s := id
265		for _, ns := range []string{"doc:", "sidecar:"} {
266			if strings.HasPrefix(s, ns) {
267				s = s[len(ns):]
268				break
269			}
270		}
271		if i := strings.IndexByte(s, '-'); i > 0 {
272			return strings.ToUpper(s[:i])
273		}
274		return ""
275	}
