379	// collectSidecarArtifacts walks .ddx/plugins/ looking for *.ddx.yaml sidecar
380	// files, then builds an Artifact for each corresponding artifact file.
381	// Files whose sidecar is missing or unreadable are silently skipped.
382	func collectSidecarArtifacts(root string) ([]*Artifact, error) {
383		pluginsDir := filepath.Join(root, ".ddx", "plugins")
384		if _, err := os.Stat(pluginsDir); os.IsNotExist(err) {
385			return nil, nil
386		}
387	
388		var out []*Artifact
389		err := filepath.WalkDir(pluginsDir, func(path string, d fs.DirEntry, err error) error {
390			if err != nil || d.IsDir() {
391				return nil
392			}
393			if !strings.HasSuffix(path, ".ddx.yaml") {
394				return nil
395			}
396	
397			// Derive artifact path by stripping the .ddx.yaml suffix.
398			artifactPath := strings.TrimSuffix(path, ".ddx.yaml")
399	
400			// Parse the sidecar.
401			data, readErr := os.ReadFile(path)
402			if readErr != nil {
403				return nil // skip unreadable sidecars
404			}
405			var sidecar ddxSidecarFile
406			if yamlErr := yaml.Unmarshal(data, &sidecar); yamlErr != nil {
407				return nil // skip malformed sidecars
408			}
409	
410			rel, relErr := filepath.Rel(root, artifactPath)
411			if relErr != nil {
412				rel = artifactPath
413			}
414	
415			id := sidecar.DDx.ID
416			if id == "" {
417				id = "sidecar:" + rel
418			}
419	
420			title := sidecar.DDx.Title
421			if title == "" {
422				title = filepath.Base(artifactPath)
423			}
424	
425			mediaType := sidecar.DDx.MediaType
426			if mediaType == "" {
427				mediaType = "application/octet-stream"
428			}
429	
430			staleness := computeSidecarStaleness(artifactPath, sidecar.DDx.GeneratedBy)
431	
432			a := &Artifact{
433				ID:        id,
434				Path:      filepath.ToSlash(rel),
435				Title:     title,
436				MediaType: mediaType,
437				Staleness: staleness,
438			}
439	
440			if sidecar.DDx.Description != "" {
441				desc := sidecar.DDx.Description
442				a.Description = &desc
443			}
444	
445			if sidecar.DDx.GeneratedBy != nil {
446				gb := sidecar.DDx.GeneratedBy
447				sourceHashMatch := false
448				if gb.SourceHash != "" {
449					if hash, hashErr := fileSHA256(artifactPath); hashErr == nil {
450						sourceHashMatch = (hash == gb.SourceHash)
451					}
452				}
453				a.GeneratedBy = &ArtifactGeneratedBy{
454					RunID:           gb.RunID,
455					PromptSummary:   gb.PromptSummary,
456					SourceHashMatch: sourceHashMatch,
457				}
458			}
459	
460			// Populate ddxFrontmatter from the raw sidecar ddx block.
461			if fm, marshalErr := json.Marshal(sidecar.DDx); marshalErr == nil {
462				s := string(fm)
463				a.DdxFrontmatter = &s
464			}
465	
466			// Populate updatedAt from artifact file mod time.
467			if info, statErr := os.Stat(artifactPath); statErr == nil {
468				ts := info.ModTime().UTC().Format(time.RFC3339)
469				a.UpdatedAt = &ts
470			}
471	
472			out = append(out, a)
473			return nil
474		})
475		if err != nil {
476			return nil, err
477		}
478		return out, nil
479	}
480	
481	// computeSidecarStaleness returns the staleness of a sidecar artifact.
482	func computeSidecarStaleness(artifactPath string, gb *ddxGeneratedBy) string {
483		if _, err := os.Stat(artifactPath); os.IsNotExist(err) {
484			return "missing"
485		}
486		if gb == nil || gb.SourceHash == "" {
487			return "fresh"
488		}
489		hash, err := fileSHA256(artifactPath)
490		if err != nil {
491			return "fresh" // can't determine staleness without a hash
492		}
493		if hash == gb.SourceHash {
494			return "fresh"
495		}
496		return "stale"
497	}
498	
499	// fileSHA256 returns the hex-encoded SHA-256 hash of a file's contents.
500	func fileSHA256(path string) (string, error) {
501		data, err := os.ReadFile(path)
502		if err != nil {
503			return "", err
504		}
505		h := sha256.Sum256(data)
506		return hex.EncodeToString(h[:]), nil
507	}
508	
509	// titleFromDoc derives a human-readable title from a docgraph document.
510	// Uses the Title field if set, otherwise derives from the path's base name.
511	func titleFromDoc(d docgraph.Document) string {
512		if d.Title != "" {
513			return d.Title
514		}
515		base := filepath.Base(d.Path)
516		// Strip extension.
517		if idx := strings.LastIndex(base, "."); idx > 0 {
518			base = base[:idx]
519		}
520		return base
521	}
