523	// Artifact is the resolver for the artifact(projectID, id) query.
524	// It returns a single artifact by ID, loading file content for text-based media types.
525	func (r *queryResolver) Artifact(ctx context.Context, projectID string, id string) (*Artifact, error) {
526		root := r.projectRoot(projectID)
527		artifacts, err := collectArtifacts(root)
528		if err != nil {
529			return nil, fmt.Errorf("collecting artifacts: %w", err)
530		}
531		for _, a := range artifacts {
532			if a.ID == id {
533				if isTextMediaType(a.MediaType) {
534					a.Content = loadArtifactContent(root, a.Path)
535				}
536				return a, nil
537			}
538		}
539		return nil, nil
540	}
541	
542	// isTextMediaType reports whether the media type has text content suitable
543	// for inline rendering (markdown, SVG, Excalidraw JSON).
544	func isTextMediaType(mt string) bool {
545		return mt == "text/markdown" || mt == "image/svg+xml" || mt == "application/vnd.excalidraw+json"
546	}
547	
548	// loadArtifactContent reads the raw file content for an artifact at the given
549	// project-relative path. Returns nil if the file cannot be read.
550	func loadArtifactContent(root, relPath string) *string {
551		absPath := filepath.Join(root, filepath.FromSlash(relPath))
552		data, err := os.ReadFile(absPath)
553		if err != nil {
554			return nil
555		}
556		s := string(data)
557		return &s
558	}
