76	// StartWorker is the resolver for the startWorker field.
77	//
78	// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
79	// project's .ddx/config.yaml drives default harness/profile/effort/label
80	// values when the GraphQL input leaves them unset. Input fields are layered
81	// onto config as CLIOverrides — when present they win over the on-disk
82	// values. The resolved values are forwarded to ActionDispatcher (and ultimately
83	// to runWorker, which re-loads config to drive the loop's durable knobs like
84	// review_max_retries / no_progress_cooldown / heartbeat_interval). This
85	// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
86	// shadowed the on-disk config.
87	func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
88		if r.Actions == nil {
