96		}
97		if input.Profile != nil {
98			overrides.Profile = strings.TrimSpace(*input.Profile)
99		}
100		if input.Effort != nil {
101			overrides.Effort = strings.TrimSpace(*input.Effort)
102		}
103		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
104	
105		args := map[string]string{}
106		if v := rcfg.Harness(); v != "" {
107			args["harness"] = v
108		}
109		profile := rcfg.Profile()
110		if profile == "" {
111			profile = "smart"
