415	// PaletteSearch is the resolver for the paletteSearch field.
416	func (r *queryResolver) PaletteSearch(ctx context.Context, query string) (*PaletteSearchResults, error) {
417		q := strings.TrimSpace(query)
418		out := &PaletteSearchResults{
419			Documents:  []*PaletteDocumentResult{},
420			Beads:      []*PaletteBeadResult{},
421			Actions:    []*PaletteActionResult{},
422			Navigation: []*PaletteNavigationResult{},
423		}
424		if q == "" {
425			return out, nil
426		}
427	
428		matches := collectPaletteMatches(q, r.WorkingDir)
429		sort.SliceStable(matches, func(i, j int) bool {
430			if matches[i].score != matches[j].score {
431				return matches[i].score < matches[j].score
432			}
433			return matches[i].sortKey < matches[j].sortKey
434		})
435		if len(matches) > paletteResultCap {
436			matches = matches[:paletteResultCap]
437		}
438		for _, match := range matches {
439			switch match.kind {
440			case "document":
441				out.Documents = append(out.Documents, &PaletteDocumentResult{Kind: "document", Path: match.id, Title: match.title})
442			case "bead":
443				out.Beads = append(out.Beads, &PaletteBeadResult{Kind: "bead", ID: match.id, Title: match.title})
444			case "action":
445				out.Actions = append(out.Actions, &PaletteActionResult{Kind: "action", ID: match.id, Label: match.title})
446			case "nav":
447				out.Navigation = append(out.Navigation, &PaletteNavigationResult{Kind: "nav", Route: match.id, Title: match.title})
448			}
449		}
450		return out, nil
451	}
