564	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
565		dir := filepath.Join(workingDir, ".ddx", "comparisons")
566		entries, err := os.ReadDir(dir)
567		if os.IsNotExist(err) {
568			return []comparisonDispatchRecord{}, nil
569		}
570		if err != nil {
571			return nil, err
572		}
573		records := make([]comparisonDispatchRecord, 0, len(entries))
574		for _, entry := range entries {
575			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
576				continue
577			}
578			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
579			if err != nil {
580				return nil, err
581			}
582			var record comparisonDispatchRecord
583			if err := json.Unmarshal(data, &record); err != nil {
584				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
585			}
586			if record.ID == "" {
587				continue
588			}
589			records = append(records, record)
590		}
591		sort.Slice(records, func(i, j int) bool {
592			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
593				return records[i].CreatedAt.After(records[j].CreatedAt)
594			}
595			return records[i].ID < records[j].ID
596		})
597		return records, nil
598	}
