602		if err := os.MkdirAll(dir, 0o755); err != nil {
603			return err
604		}
605		data, err := json.MarshalIndent(record, "", "  ")
606		if err != nil {
607			return err
608		}
609		data = append(data, '\n')
610		return os.WriteFile(filepath.Join(dir, id+".json"), data, 0o644)
611	}
