632	func pluginCatalog(workingDir string) ([]*PluginInfo, error) {
633		reg := registry.BuiltinRegistry()
634		state, err := registry.LoadState()
635		if err != nil {
636			return nil, err
637		}
638	
639		byName := map[string]*PluginInfo{}
640		installedByName := map[string]registry.InstalledEntry{}
641		for _, entry := range state.Installed {
642			installedByName[entry.Name] = entry
643		}
644	
645		for _, pkg := range reg.Packages {
646			info := pluginInfoFromPackage(pkg, workingDir, installedByName[pkg.Name])
647			byName[info.Name] = info
648		}
649		for _, entry := range state.Installed {
650			if _, ok := byName[entry.Name]; ok {
651				continue
652			}
653			info := pluginInfoFromInstalled(entry, workingDir)
654			byName[info.Name] = info
655		}
656	
657		out := make([]*PluginInfo, 0, len(byName))
658		for _, info := range byName {
659			out = append(out, info)
660		}
661		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
662		return out, nil
663	}
