665	func pluginInfoFromPackage(pkg registry.Package, workingDir string, installed registry.InstalledEntry) *PluginInfo {
666		info := &PluginInfo{
667			Name:           pkg.Name,
668			Version:        pkg.Version,
669			Type:           string(pkg.Type),
670			Description:    pkg.Description,
671			Keywords:       append([]string(nil), pkg.Keywords...),
672			Status:         "available",
673			RegistrySource: pkg.Source,
674			Skills:         []string{},
675			Prompts:        []string{},
676			Templates:      []string{},
677		}
678		if installed.Name != "" {
679			info.InstalledVersion = strPtr(installed.Version)
680			info.Status = "installed"
681			if installed.Version != "" && installed.Version != pkg.Version {
682				info.Status = "update-available"
683			}
684		}
685		if manifest, err := json.Marshal(pkg); err == nil {
686			info.Manifest = strPtr(string(manifest))
687		}
688		enrichPluginInfoFromDisk(info, workingDir, pkg.Name, installed)
689		return info
690	}
