745	func dirSize(root string) int {
746		var total int64
747		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
748			if err != nil || d.IsDir() {
749				return nil
750			}
751			if info, err := d.Info(); err == nil {
752				total += info.Size()
753			}
754			return nil
755		})
756		const maxInt32 = int64(1<<31 - 1)
757		if total > maxInt32 {
758			return int(maxInt32)
759		}
760		return int(total)
