769				continue
770			}
771			for _, entry := range entries {
772				if strings.HasPrefix(entry.Name(), ".") {
773					continue
774				}
775				if marker != "" {
776					if !entry.IsDir() {
777						continue
778					}
779					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
780						continue
781					}
782				}
