818		query := agent.SessionIndexQuery{
819			StartedAfter:  startedAfter,
820			StartedBefore: startedBefore,
821		}
822		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
823		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
824		if err != nil {
825			return efficacySnapshot{}, err
826		}
827		sessionEfficacyCache.Lock()
828		if sessionEfficacyCache.byQuery == nil {
829			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
830		}
831		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
832			sessionEfficacyCache.Unlock()
833			return cached.snapshot, nil
834		}
835		sessionEfficacyCache.Unlock()
