859	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
860		files, err := agent.SessionIndexShardFiles(logDir, query)
861		if err != nil {
862			return "", err
863		}
864		parts := make([]string, 0, len(files))
865		for _, file := range files {
866			info, err := os.Stat(file)
867			if os.IsNotExist(err) {
868				continue
869			}
870			if err != nil {
871				return "", err
872			}
873			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
874		}
875		return strings.Join(parts, "|"), nil
876	}
