878	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
879		if raw == nil || strings.TrimSpace(*raw) == "" {
880			return nil, nil
881		}
882		value := strings.TrimSpace(*raw)
883		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
884			if parsed, err := time.Parse(layout, value); err == nil {
885				utc := parsed.UTC()
886				return &utc, nil
887			}
888		}
889		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
890	}
