907	func buildSessionIndexEfficacySnapshot(entries []agent.SessionIndexEntry) efficacySnapshot {
908		grouped := map[string][]sessionEfficacyAttempt{}
909		for _, entry := range entries {
910			attempt := efficacyAttemptFromSession(entry)
911			if attempt.RowKey == "" {
912				continue
913			}
914			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
915		}
916		rows := make([]*EfficacyRow, 0, len(grouped))
917		attemptDetails := map[string][]*EfficacyAttempt{}
918		for rowKey, group := range grouped {
919			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
920			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
921			var inputTokens, outputTokens, durations []int
922			var costs []float64
923			var successes int
924			for _, attempt := range group {
925				if attempt.Outcome == "succeeded" {
926					successes++
927				}
928				inputTokens = append(inputTokens, attempt.InputTokens)
929				outputTokens = append(outputTokens, attempt.OutputTokens)
930				durations = append(durations, attempt.DurationMs)
931				if attempt.CostUsd != nil {
932					costs = append(costs, *attempt.CostUsd)
933				}
934				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
935					BeadID:            attempt.BeadID,
936					Outcome:           attempt.Outcome,
937					DurationMs:        attempt.DurationMs,
938					CostUsd:           attempt.CostUsd,
939					EvidenceBundleURL: attempt.EvidencePath,
940				})
941			}
942			parts := strings.Split(rowKey, "|")
943			row := &EfficacyRow{
944				RowKey:             rowKey,
945				Harness:            parts[0],
946				Provider:           parts[1],
947				Model:              parts[2],
948				Attempts:           len(group),
949				Successes:          successes,
950				SuccessRate:        float64(successes) / float64(len(group)),
951				MedianInputTokens:  medianInt(inputTokens),
952				MedianOutputTokens: medianInt(outputTokens),
953				MedianDurationMs:   medianInt(durations),
954				MedianCostUsd:      medianFloatPtr(costs),
955			}
956			if row.SuccessRate < efficacyWarningFloor {
957				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
958			}
959			rows = append(rows, row)
960		}
961		sort.Slice(rows, func(i, j int) bool {
962			if rows[i].SuccessRate != rows[j].SuccessRate {
963				return rows[i].SuccessRate > rows[j].SuccessRate
964			}
965			return rows[i].RowKey < rows[j].RowKey
966		})
967	
968		return efficacySnapshot{rows: rows, attempts: attemptDetails}
969	}
