1092	func paletteScore(query string, fields ...string) (int, bool) {
1093		q := strings.ToLower(strings.TrimSpace(query))
1094		if q == "" {
1095			return 0, false
1096		}
1097		terms := strings.Fields(q)
1098		best := 1000
1099		for _, field := range fields {
1100			f := strings.ToLower(field)
1101			if strings.HasPrefix(f, q) {
1102				best = min(best, 0)
1103				continue
1104			}
1105			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
1106				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
1107			}) {
1108				if strings.HasPrefix(part, q) {
1109					best = min(best, 1)
1110				}
1111			}
1112			allTerms := true
1113			for _, term := range terms {
1114				if !strings.Contains(f, term) {
1115					allTerms = false
1116					break
1117				}
1118			}
1119			if allTerms {
1120				best = min(best, 2)
1121			}
1122		}
1123		if best == 1000 {
1124			return 0, false
1125		}
1126		return best, true
1127	}
