273	// TestArtifacts_SortAllValuesTieBreak runs every ArtifactSort enum value
274	// through the resolver and asserts that ties on the primary key fall back to
275	// ascending id ordering — the contract that makes cursor pagination
276	// deterministic when filters or sorts change.
277	func TestArtifacts_SortAllValuesTieBreak(t *testing.T) {
278		t.Setenv("HOME", t.TempDir())
279		workDir, store := setupIntegrationDir(t)
280		workDir = setupArtifactFixtureInDir(t, workDir)
281	
282		srv := httptest.NewServer(newArtifactGQLHandler(workDir, store))
283		defer srv.Close()
284	
285		projID := "proj-integration-" + filepath.Base(workDir)
286	
287		type sortKey struct {
288			name   string
289			field  string // node field used as the primary sort key for the assertion
290			gqlVal string
291		}
292		keys := []sortKey{
293			{"ID", "id", "ID"},
294			{"PATH", "path", "PATH"},
295			{"TITLE", "title", "TITLE"},
296			{"MODIFIED", "updatedAt", "MODIFIED"},
297			{"DEPS_COUNT", "id", "DEPS_COUNT"}, // depsCount is not exposed; verify only the id tie-breaker
298		}
299	
300		for _, k := range keys {
301			t.Run(k.name, func(t *testing.T) {
302				body := bytes.NewBufferString(`{"query":"{ artifacts(projectID: \"` + projID + `\", sort: ` + k.gqlVal + `) { edges { node { id path title updatedAt } } } }"}`)
303				resp, err := http.Post(srv.URL+"/graphql", "application/json", body)
304				if err != nil {
305					t.Fatal(err)
306				}
307				defer resp.Body.Close()
308	
309				var result map[string]interface{}
310				if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
311					t.Fatal(err)
312				}
313				if errs, ok := result["errors"]; ok {
314					t.Fatalf("GraphQL errors: %v", errs)
315				}
316				edges := result["data"].(map[string]interface{})["artifacts"].(map[string]interface{})["edges"].([]interface{})
317				if len(edges) < 2 {
318					t.Fatalf("need ≥2 artifacts to verify ordering, got %d", len(edges))
319				}
320	
321				var prevPrimary, prevID string
322				for i, e := range edges {
323					node := e.(map[string]interface{})["node"].(map[string]interface{})
324					id := node["id"].(string)
325					var primary string
326					if v, ok := node[k.field]; ok && v != nil {
327						primary, _ = v.(string)
328					}
329					if i > 0 {
330						if primary < prevPrimary {
331							t.Errorf("sort=%s: primary key not ascending at index %d: %q before %q", k.name, i, prevPrimary, primary)
332						}
333						if primary == prevPrimary && id < prevID {
334							t.Errorf("sort=%s: id tie-breaker violated at index %d: %q before %q", k.name, i, prevID, id)
335						}
336					}
337					prevPrimary, prevID = primary, id
338				}
339			})
340		}
341	}
